<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        cacheDeleteProducer.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cacheKey);</span></span>
